use distributed_inference::pleromatic_knot_storage::KnotStorage;
use std::env;

/// get-swarm-history: Retrieve the last N vibe frames from the Pleromatic mesh.
///
/// Usage: get-swarm-history [limit]
fn main() -> std::io::Result<()> {
    let args: Vec<String> = env::args().collect();
    let limit = args
        .get(1)
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(24);

    let storage = KnotStorage::new("assets/memory");

    match storage.history(limit) {
        Ok(frames) => {
            let json = serde_json::to_string_pretty(&frames)
                .map_err(std::io::Error::other)?;
            println!("{}", json);
        }
        Err(e) => {
            eprintln!("Failed to retrieve swarm history: {}", e);
            std::process::exit(1);
        }
    }

    Ok(())
}
